/**
 * dsa-visualisation.js — Image slideshow + Step-by-Step/Animation tab switch.
 * Operates on the .viz-panel structure generated by build.py's
 * expand_visualisation() function.
 * File: js/notes/dsa/dsa-visualisation.js
 */

(function () {
    'use strict';

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initVisualisation);
    } else {
        initVisualisation();
    }

    function initVisualisation() {
        const panel = document.querySelector('.viz-panel');
        if (!panel) {
            console.log('ℹ️ No visualisation panel on this page');
            return;
        }

        initTabSwitch(panel);
        initImageSlideshow(panel);

        console.log('✅ DSA visualisation initialized');
    }

    function initTabSwitch(panel) {
        const tabImages    = panel.querySelector('#tab-images');
        const tabAnimation = panel.querySelector('#tab-animation');
        const viewImages    = panel.querySelector('#viz-images');
        const viewAnimation = panel.querySelector('#viz-animation');

        if (!tabImages || !tabAnimation) return;

        tabImages.addEventListener('click', () => {
            tabImages.classList.add('active');
            tabImages.setAttribute('aria-selected', 'true');
            tabAnimation.classList.remove('active');
            tabAnimation.setAttribute('aria-selected', 'false');

            if (viewImages)    viewImages.style.display = 'block';
            if (viewAnimation) viewAnimation.style.display = 'none';
        });

        tabAnimation.addEventListener('click', () => {
            tabAnimation.classList.add('active');
            tabAnimation.setAttribute('aria-selected', 'true');
            tabImages.classList.remove('active');
            tabImages.setAttribute('aria-selected', 'false');

            if (viewAnimation) viewAnimation.style.display = 'block';
            if (viewImages)    viewImages.style.display = 'none';
        });
    }

    function initImageSlideshow(panel) {
        const images = panel.querySelectorAll('.viz-step-img');
        const prevBtn = panel.querySelector('#viz-prev');
        const nextBtn = panel.querySelector('#viz-next');
        const currentEl = panel.querySelector('#viz-current');
        const captionEl = panel.querySelector('#viz-caption');

        if (images.length === 0) return;

        let current = 0;
        const total = images.length;

        function showStep(idx) {
            images.forEach((img, i) => {
                img.classList.toggle('active', i === idx);
            });

            if (currentEl) currentEl.textContent = idx + 1;
            if (captionEl) captionEl.textContent = images[idx].dataset.caption || '';
            if (prevBtn) prevBtn.disabled = (idx === 0);
            if (nextBtn) nextBtn.disabled = (idx === total - 1);

            current = idx;
        }

        if (prevBtn) {
            prevBtn.addEventListener('click', () => {
                if (current > 0) showStep(current - 1);
            });
        }

        if (nextBtn) {
            nextBtn.addEventListener('click', () => {
                if (current < total - 1) showStep(current + 1);
            });
        }

        // Keyboard navigation when panel is focused
        panel.addEventListener('keydown', (e) => {
            if (e.key === 'ArrowLeft' && current > 0) showStep(current - 1);
            if (e.key === 'ArrowRight' && current < total - 1) showStep(current + 1);
        });

        showStep(0);
    }

})();
